#include <bits/stdc++.h>
using namespace std;

const int N=210;

int n,m,t,vis[N],match[N];
bool b[N][N];
vector<int> g[N];

bool dfs(int x){
    for(int y:g[x])
        if(!vis[y]){
            vis[y]=1;
            if(!match[y] || dfs(match[y])){
                match[y]=x;
                return 1;
            }
        }
    return 0;
}

int main(){
    scanf("%d%d%d",&n,&m,&t);
    while(t--){
        int x,y;
        scanf("%d%d",&x,&y);
        b[x][y]=1;
    }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            if(!b[i][j])
                g[i].push_back(j);
    int ans=0;
    for(int i=1;i<=n;i++){
        memset(vis,0,sizeof(vis));
        if(dfs(i))
            ans++;
    }
    printf("%d",ans);
    return 0;
}
